import sys
from collections import deque

def main():
    H, W = map(int, sys.stdin.readline().split())
    grid = [sys.stdin.readline().strip() for _ in range(H)]
    target = "snuke"
    mod = 5

    # Directions: up, down, left, right
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    # dp[i][j][k] = True if we can reach (i, j) with the k-th character of "snuke"
    dp = [[[False] * mod for _ in range(W)] for _ in range(H)]

    # Starting point (1,1) is (0,0) in 0-based index
    dp[0][0][(0) % mod] = True

    for i in range(H):
        for j in range(W):
            for k in range(mod):
                if dp[i][j][k]:
                    for dx, dy in directions:
                        ni, nj = i + dx, j + dy
                        if 0 <= ni < H and 0 <= nj < W:
                            next_k = (k + 1) % mod
                            if grid[ni][nj] == target[next_k]:
                                dp[ni][nj][next_k] = True

    # Check if (H-1, W-1) can be reached with the correct character
    if dp[H-1][W-1][(mod - 1) % mod]:
        print("Yes")
    else:
        print("No")

main()
